const main = async () => {
  let ImapFlow;
  try {
    ({ ImapFlow } = require('imapflow'));
  } catch (e) {
    return [
      {
        json: {
          status: 'error',
          message:
            'IMAP-Module nicht geladen. Auf dem Server NODE_FUNCTION_ALLOW_EXTERNAL=imapflow,mailparser setzen und npm-Pakete installieren.',
        },
      },
    ];
  }

  let simpleParser = null;
  try {
    simpleParser = require('mailparser').simpleParser;
  } catch (e) {
    /* optional */
  }

  const raw = $input.first().json;
  let body = raw.body;
  if (typeof body === 'string') {
    try {
      body = JSON.parse(body || '{}');
    } catch (e) {
      return [{ json: { status: 'error', message: 'Ungültiges JSON im Body' } }];
    }
  }
  if (!body || typeof body !== 'object') {
    return [{ json: { status: 'error', message: 'Ungültiger Request-Body' } }];
  }

  const emailAddr = body.email;
  const password = body.password;
  const server = body.server;
  const port = parseInt(String(body.port ?? 993), 10) || 993;
  const folder = body.folder || 'INBOX';
  const limit = 50;
  const insecureTls = body.insecureTls === true || body.insecureTls === 'true';

  if (!emailAddr || !password || !server) {
    return [
      {
        json: {
          status: 'error',
          message: 'email, password und server sind erforderlich',
        },
      },
    ];
  }

  const client = new ImapFlow({
    host: server,
    port,
    secure: port === 993,
    tls: insecureTls ? { rejectUnauthorized: false } : undefined,
    auth: { user: emailAddr, pass: password },
    logger: false,
  });

  try {
    await client.connect();
  } catch (e) {
    return [
      {
        json: {
          status: 'error',
          message: 'Verbindungsfehler: ' + (e.message || String(e)),
        },
      },
    ];
  }

  function hasAttachmentInStructure(part) {
    if (!part) return false;
    if (part.disposition === 'attachment') return true;
    if (part.type === 'multipart' && Array.isArray(part.childNodes)) {
      return part.childNodes.some(hasAttachmentInStructure);
    }
    return false;
  }

  try {
    await client.mailboxOpen(folder);
    const total =
      client.mailbox && typeof client.mailbox.exists === 'number' ? client.mailbox.exists : 0;
    const emails = [];

    if (total > 0) {
      const start = Math.max(1, total - limit + 1);
      const range = `${start}:${total}`;
      for await (const msg of client.fetch(range, {
        uid: true,
        envelope: true,
        internalDate: true,
        flags: true,
        source: true,
        bodyStructure: true,
      })) {
        const env = msg.envelope || {};
        const fromAddr = env.from && env.from[0];
        const toAddr = env.to && env.to[0];
        let bodyText = '';
        let hasAtt = false;

        if (msg.source && simpleParser) {
          try {
            const parsed = await simpleParser(msg.source);
            bodyText =
              parsed.text ||
              (typeof parsed.html === 'string' ? parsed.html.replace(/<[^>]+>/g, ' ') : '') ||
              '';
            hasAtt = !!(parsed.attachments && parsed.attachments.length > 0);
          } catch (e) {
            bodyText = msg.source.toString('utf8').substring(0, 20000);
          }
        } else if (msg.source) {
          bodyText = msg.source.toString('utf8').substring(0, 20000);
        }

        if (!hasAtt && msg.bodyStructure) {
          hasAtt = hasAttachmentInStructure(msg.bodyStructure);
        }

        const preview = bodyText.replace(/\s+/g, ' ').trim().substring(0, 120);
        const seen = msg.flags && msg.flags.has ? msg.flags.has('\\Seen') : false;
        const flagged = msg.flags && msg.flags.has ? msg.flags.has('\\Flagged') : false;

        emails.push({
          id: `msg-${msg.uid}`,
          from: (fromAddr && fromAddr.address) || '',
          fromName: (fromAddr && (fromAddr.name || fromAddr.address)) || '',
          to: (toAddr && toAddr.address) || emailAddr,
          subject: env.subject || '',
          preview: preview || '',
          body: bodyText,
          date: msg.internalDate
            ? new Date(msg.internalDate).toISOString()
            : new Date().toISOString(),
          hasAttachment: hasAtt,
          read: seen,
          starred: flagged,
        });
      }
    }

    emails.reverse();
    await client.logout();
    return [{ json: { status: 'success', emails } }];
  } catch (e) {
    try {
      await client.logout();
    } catch (_) {}
    return [
      {
        json: {
          status: 'error',
          message: 'Verbindungsfehler: ' + (e.message || String(e)),
        },
      },
    ];
  }
};

return await main();
